import websocket
import json

class WebSocketServer(websocket.WebSocket):
    def __init__(self, host, port):
        self.host = host
        self.port = port
        self.ws = None
    
    def start(self):
        self.ws = websocket.WebSocket()
        self.ws.connect("ws://{}:{}".format(self.host, self.port))
    
    def stop(self):
        self.ws.close()
    
    def handle_message(self, message):
        data = json.loads(message)
        if "action" in data:
            action = data["action"]
            if action == "turn_on":
                # Handle turn on command
                print("Turning on device")
            elif action == "turn_off":
                # Handle turn off command
                print("Turning off device")
            else:
                # Unknown action, ignore it
                pass
        else:
            # No action specified, ignore message
            pass
    
    def send_message(self, message):
        self.ws.send(json.dumps(message))